     6→/// Yet another smartphone camera library.
     7→
     8→import 'package:flutter/foundation.dart';
     9→import 'package:flutter/services.dart';
    10→
    11→/// Camera lens data class.
    12→///
    13→/// Note that this class presents "logical camera lens".
    14→/// In some modern android devices, several physical camera lenses
    15→/// (i.e., physical cameras) compose one logical camera lens.
    16→/// A logical camera automatically changes physical camera lenses
    17→/// in response to its zoom value.
    18→class Lens {
    19→  final int index;
    20→  final String description;
    21→
    22→  Lens(this.index, this.description);
    23→
    24→  bool get isWideAngle => description == "WideAngle";
    25→  bool get isTelephoto => description == "Telephoto";
    26→}
    27→
    28→/// Camera format data class.
    29→///
    30→/// Format contains resolution, FPS, focal length and so on.
    31→class Format {
    32→  final int index;
    33→  final int landscapeWidth;
    34→  final int landscapeHeight;
    35→  final double fps;
    36→  final double videoFieldOfView;
    37→  final bool binned;
    38→  final bool hdr;
    39→  final bool stabilization;
    40→
    41→  const Format({
    42→    required this.index,
    43→    required this.landscapeWidth,
    44→    required this.landscapeHeight,
    45→    required this.fps,
    46→    required this.videoFieldOfView,
    47→    required this.binned,
    48→    required this.hdr,
    49→    required this.stabilization,
    50→  });
    51→
    52→  bool get isFullHD =>
    53→      landscapeWidth == 1920 && landscapeHeight == 1080 ||
    54→      landscapeWidth == 1080 && landscapeHeight == 1920;
    55→
    56→  bool get is4K =>
    57→      landscapeWidth == 3840 && landscapeHeight == 2160 ||
    58→      landscapeWidth == 2160 && landscapeHeight == 3840;
    59→}
    60→
    61→/// The interface to communicate native camera APIs via MethodChannel.
    62→class KnowhereConfigurableCamera {
    63→  static const platformViewID = 'knowhere_configurable_camera/view';
    64→  static const methodChannelID = 'knowhere_configurable_camera/method';
    65→  static const eventChannelID = 'knowhere_configurable_camera/event';
    66→  static const cameraErrorChannelID =
    67→      'knowhere_configurable_camera/camera_error';
    68→  static const recordingStateChannelID =
    69→      'knowhere_configurable_camera/recording_state';
    70→
    71→  static const _methodChannel = MethodChannel(methodChannelID);
    72→  static const _cameraErrorChannel = EventChannel(cameraErrorChannelID);
    73→  static const _recordingStateChannel = EventChannel(recordingStateChannelID);
    74→
    75→  static final _singletonObject = KnowhereConfigurableCamera();
    76→
    77→  static KnowhereConfigurableCamera getSingletonObject() {
    78→    return _singletonObject;
    79→  }
    80→
    81→  StreamSubscription<bool>? _streamSubscription;
    82→  bool _isSessionConfigured = false;
    83→  bool _isRecording = false;
    84→  bool get isSessionConfigured => _isSessionConfigured;
    85→  bool get isRecording => _isRecording;
    86→
    87→  KnowhereConfigurableCamera();
    88→
    89→  /// This method initializes a camera session.
    90→  Future<int> configureSession({VoidCallback? onVolumeKeyPressed}) async {
    91→    final arguments = {};
    92→    final cameraId =
    93→        await _methodChannel.invokeMethod('configureSession', arguments);
    94→    _isSessionConfigured = true;
    95→
    96→    if (Platform.isIOS) {
    97→      await _streamSubscription?.cancel();
    98→      _streamSubscription = _recordingStateChannel
    99→          .receiveBroadcastStream(recordingStateChannelID)
   100→          .cast<bool>()
   101→          .listen(
   102→        (_) {
   103→          onVolumeKeyPressed?.call();
   104→        },
   105→        onError: (error) {
   106→          debugPrint('Recording state stream error: $error');
   107→        },
   108→      );
   109→    }
   110→
   111→    return cameraId;
   112→  }
   113→
   114→  /// This method closes the running camera session.
   115→  Future<void> closeSession() async {
   116→    _checkSessionConfiguration();
   117→
   118→    _streamSubscription?.cancel();
   119→    _streamSubscription = null;
   120→    _isSessionConfigured = false;
   121→    _isRecording = false;
   122→    final arguments = {};
   123→    return await _methodChannel.invokeMethod('closeSession', arguments);
   124→  }
   125→
   126→  void _checkSessionConfiguration() {
   127→    if (!_isSessionConfigured) {
   128→      throw StateError("Camera session is not configured.");
   129→    }
   130→  }
   131→
   132→  /// This method connects a camera session and a camera preview view.
   133→  ///
   134→  /// Note that generating two or more preview is impossible in this library.
   135→  Future<String> connect() async {
   136→    _checkSessionConfiguration();
   137→
   138→    final arguments = {};
   139→    final String message =
   140→        await _methodChannel.invokeMethod('connect', arguments);
   141→    return message;
   142→  }
   143→
   144→  Future<int> getOrientationAngle() async {
   145→    _checkSessionConfiguration();
   146→
   147→    final arguments = {};
   148→    final int angle =
   149→        await _methodChannel.invokeMethod('getOrientationAngle', arguments);
   150→    return angle;
   151→  }
   152→
   153→  Future<bool> onPause() async {
   154→    _checkSessionConfiguration();
   155→
   156→    final arguments = {};
   157→    return await _methodChannel.invokeMethod('onPause', arguments);
   158→  }
   159→
   160→  Future<bool> onResume() async {
   161→    _checkSessionConfiguration();
