library;

import 'dart:async';
import 'dart:io';

/// Yet another smartphone camera library.

import 'package:flutter/foundation.dart';
import 'package:flutter/services.dart';

/// Camera lens data class.
///
/// Note that this class presents "logical camera lens".
/// In some modern android devices, several physical camera lenses
/// (i.e., physical cameras) compose one logical camera lens.
/// A logical camera automatically changes physical camera lenses
/// in response to its zoom value.
class Lens {
  final int index;
  final String description;

  Lens(this.index, this.description);

  bool get isWideAngle => description == "WideAngle";
  bool get isTelephoto => description == "Telephoto";
}

/// Camera format data class.
///
/// Format contains resolution, FPS, focal length and so on.
class Format {
  final int index;
  final int landscapeWidth;
  final int landscapeHeight;
  final double fps;
  final double videoFieldOfView;
  final bool binned;
  final bool hdr;
  final bool stabilization;

  const Format({
    required this.index,
    required this.landscapeWidth,
    required this.landscapeHeight,
    required this.fps,
    required this.videoFieldOfView,
    required this.binned,
    required this.hdr,
    required this.stabilization,
  });

  bool get isFullHD =>
      landscapeWidth == 1920 && landscapeHeight == 1080 ||
      landscapeWidth == 1080 && landscapeHeight == 1920;

  bool get is4K =>
      landscapeWidth == 3840 && landscapeHeight == 2160 ||
      landscapeWidth == 2160 && landscapeHeight == 3840;
}

/// The interface to communicate native camera APIs via MethodChannel.
class KnowhereConfigurableCamera {
  static const platformViewID = 'knowhere_configurable_camera/view';
  static const methodChannelID = 'knowhere_configurable_camera/method';
  static const eventChannelID = 'knowhere_configurable_camera/event';
  static const cameraErrorChannelID =
      'knowhere_configurable_camera/camera_error';
  static const recordingStateChannelID =
      'knowhere_configurable_camera/recording_state';

  static const _methodChannel = MethodChannel(methodChannelID);
  static const _cameraErrorChannel = EventChannel(cameraErrorChannelID);
  static const _recordingStateChannel = EventChannel(recordingStateChannelID);

  static final _singletonObject = KnowhereConfigurableCamera();

  static KnowhereConfigurableCamera getSingletonObject() {
    return _singletonObject;
  }

  StreamSubscription<bool>? _streamSubscription;
  bool _isSessionConfigured = false;
  bool _isRecording = false;
  bool get isSessionConfigured => _isSessionConfigured;
  bool get isRecording => _isRecording;

  KnowhereConfigurableCamera();

  /// This method initializes a camera session.
  Future<int> configureSession({VoidCallback? onVolumeKeyPressed}) async {
    final arguments = {};
    final cameraId =
        await _methodChannel.invokeMethod('configureSession', arguments);
    _isSessionConfigured = true;

    if (Platform.isIOS) {
      await _streamSubscription?.cancel();
      _streamSubscription = _recordingStateChannel
          .receiveBroadcastStream(recordingStateChannelID)
          .cast<bool>()
          .listen(
        (_) {
          onVolumeKeyPressed?.call();
        },
        onError: (error) {
          debugPrint('Recording state stream error: $error');
        },
      );
    }

    return cameraId;
  }

  /// This method closes the running camera session.
  Future<void> closeSession() async {
    _checkSessionConfiguration();

    _streamSubscription?.cancel();
    _streamSubscription = null;
    _isSessionConfigured = false;
    _isRecording = false;
    final arguments = {};
    return await _methodChannel.invokeMethod('closeSession', arguments);
  }

  void _checkSessionConfiguration() {
    if (!_isSessionConfigured) {
      throw StateError("Camera session is not configured.");
    }
  }

  /// This method connects a camera session and a camera preview view.
  ///
  /// Note that generating two or more preview is impossible in this library.
  Future<String> connect() async {
    _checkSessionConfiguration();

    final arguments = {};
    final String message =
        await _methodChannel.invokeMethod('connect', arguments);
    return message;
  }

  Future<int> getOrientationAngle() async {
    _checkSessionConfiguration();

    final arguments = {};
    final int angle =
        await _methodChannel.invokeMethod('getOrientationAngle', arguments);
    return angle;
  }

  Future<bool> onPause() async {
    _checkSessionConfiguration();

    final arguments = {};
    return await _methodChannel.invokeMethod('onPause', arguments);
  }

  Future<bool> onResume() async {
    _checkSessionConfiguration();

    final arguments = {};
    return await _methodChannel.invokeMethod('onResume', arguments);
  }

  Future<bool?> isSupportedDevice() async {
    _checkSessionConfiguration();

    final arguments = {};
    final bool? result =
        await _methodChannel.invokeMethod('isSupportedDevice', arguments);
    return result;
  }

  Future<bool?> isStabilizationSupportedDevice() async {
    _checkSessionConfiguration();

    final arguments = {};
    final bool? result = await _methodChannel.invokeMethod(
        'isStabilizationSupportedDevice', arguments);
    return result;
  }

  /// Query start recording to native camera device if it is not recording.
  ///
  /// Returns file path with extension.
  /// Extension and file format are decided by native side.
  Future<String> startRecording(String filePath) async {
    _checkSessionConfiguration();

    if (_isRecording) {
      return "already recording";
    }

    _isRecording = true;

    final arguments = {'url': filePath};
    final filePathWithExt =
        await _methodChannel.invokeMethod('startRecording', arguments);
    return filePathWithExt;
  }

  /// Query stop recording to native camera device if it is recording.
  ///
  /// Returns true if it is recording and the camera device returned succeeded.
  /// Otherwise it returns false.
  Future<bool> stopRecording() async {
    _checkSessionConfiguration();

    if (!_isRecording) {
