        let methodChannel = FlutterMethodChannel(
            name: "knowhere_configurable_camera/method",
            binaryMessenger: registrar.messenger())
        let cameraErrorChannel = FlutterEventChannel(
            name: "knowhere_configurable_camera/camera_error",
            binaryMessenger: registrar.messenger())
        let recordingStateChannel = FlutterEventChannel(
            name: "knowhere_configurable_camera/recording_state",
            binaryMessenger: registrar.messenger())

        let instance = KnowhereConfigurableCameraPlugin()
        registrar.addMethodCallDelegate(instance, channel: methodChannel)
        cameraErrorChannel.setStreamHandler(instance)
        recordingStateChannel.setStreamHandler(instance)
    }

