// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:collection/collection.dart';
import 'package:flutter_hooks/flutter_hooks.dart';
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/resource_data_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/team_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/user_accessible_contents_controller.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/data/models/paging_data.dart';
import 'package:baseball_detector_flutter/data/models/resource.dart';
import 'package:baseball_detector_flutter/data/models/session.dart';
import 'package:baseball_detector_flutter/data/result.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/utils/build_context_ext.dart';
import 'package:baseball_detector_flutter/utils/dark_mode_ext.dart';
import 'package:baseball_detector_flutter/utils/platform.dart';
import 'package:baseball_detector_flutter/views/components/custom_app_bar.dart';
import 'package:baseball_detector_flutter/views/components/custom_loading_indicator.dart';
import 'package:baseball_detector_flutter/views/components/empty_view.dart';
import 'package:baseball_detector_flutter/views/components/paging_helper.dart';
import 'package:baseball_detector_flutter/views/hooks/use_access_denied_navigation.dart';
import 'package:baseball_detector_flutter/views/hooks/use_debounce.dart';
import 'package:baseball_detector_flutter/views/pages/home/home_page.dart';
import 'package:baseball_detector_flutter/views/pages/home/hooks/use_subscription.dart';
import 'package:baseball_detector_flutter/views/pages/home/hooks/use_subscription_page.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/components/usage_limit_alert_snack_bar.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/components/resource_card.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/components/session_meta_data_menu_anchor.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/components/session_scatter_chart.dart';
import 'package:baseball_detector_flutter/views/routers/app_router.dart';
import 'package:baseball_detector_flutter/views/routers/home_router.dart';
import 'package:baseball_detector_flutter/views/themes/color_manager.dart';

/// A page widget class to display data of a session.
/// It shows the list of the resources (i.e., videos and their analysis results) associated to the session.
/// By tapping an analyzed resource item, its `ResourceDetailsPage` will open.
/// Uploading local videos and re-analyzing failed videos also will be managed by this widget.
class SessionDetailsPage extends HookConsumerWidget {
  const SessionDetailsPage({
    required this.session,
    required this.teamId,
    required this.sessionId,
    super.key,
  });

  final String teamId;
  final String sessionId;
  final Session session;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final handleAccessDenied = useAccessDeniedNavigation();
    final currentSession = useState<Session>(session);
    final resourceState = ref.watch(
      resourceDataListControllerProvider(
        teamId: teamId,
        sessionId: sessionId,
      ),
    );

    return resourceState.when(
      data: (resourceData) => _SessionDetailsPageContent(
        resourcePagingData: resourceData,
        session: currentSession.value,
        teamId: teamId,
        onSessionUpdated: (updatedSession) {
          currentSession.value = updatedSession;
        },
      ),
      loading: () => Scaffold(
        appBar: CustomAppBar(isBackNavigation: true),
        body: const CustomLoadingIndicator(),
      ),
      error: (error, stackTrace) {
        if (error is ForbiddenFailure) {
          handleAccessDenied();
          return const SizedBox.shrink();
        }

        return Scaffold(
          appBar: CustomAppBar(isBackNavigation: true),
          floatingActionButton: FloatingActionButton(
            backgroundColor: context.isDarkMode
                ? ColorManager.darkSecondaryText
                : ColorManager.secondaryText,
            onPressed: null,
            child: Icon(Icons.videocam_outlined),
          ),
          body: Center(
            child: Column(
              mainAxisSize: MainAxisSize.min,
              children: [
                IconButton(
                  onPressed: () {
                    ref
                      ..invalidate(resourceDataListControllerProvider(
                        teamId: teamId,
                        sessionId: sessionId,
                      ))
                      ..invalidate(teamListControllerProvider);
                  },
                  icon: const Icon(Icons.refresh),
                ),
                Text(context.l10n.get_data_failed),
                const Gap(8),
                Text(
                  (error is Failure)
                      ? error.translate(context.l10n)
                      : error.toString(),
                  textAlign: TextAlign.center,
                ),
              ],
            ),
          ),
        );
      },
    );
  }
}

class _SessionDetailsPageContent extends HookConsumerWidget {
  const _SessionDetailsPageContent({
    required this.resourcePagingData,
    required this.session,
    required this.teamId,
    required this.onSessionUpdated,
  });

  final PagingData<ResourceData> resourcePagingData;
  final Session session;
  final String teamId;
  final void Function(Session) onSessionUpdated;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final showSubscriptionPage = useSubscriptionPage();
    final goToSubscription = useDebounce(showSubscriptionPage);
    final tabController = useTabController(initialLength: 2);
    final currentSession = useState<Session>(session);
    final accessibleContents =
        ref.watch(userAccessibleContentsControllerProvider);
    final userId = ref.watch(profileStorageProvider).getUserId();
    final teamList = ref.watch(teamListControllerProvider);
    final (canSubscribe, subscriptionStatus, restrictionMessage) =
        useSubscription();
    final isRecordingAvailable = teamList.fold(
      loading: () => null,
      error: (_) => null,
      data: (teams) =>
          currentSession.value
              .isVideoUploadableByUser(userId!, accessibleContents!) &&
          (teams
                  .where((team) => team.id == teamId)
                  .firstOrNull
                  ?.teamPlan
                  ?.isAvailable ??
              false),
    );

    return Scaffold(
      appBar: AppBar(
        leading: IconButton(
          tooltip: "Back",
          icon: Icon(
            isIos ? Icons.arrow_back_ios_new : Icons.arrow_back,
            size: 20,
          ),
          onPressed: () {
            Navigator.of(context).pop(true);
          },
        ),
        title: SessionMetaDataMenuAnchor(session: currentSession.value),
        actions: [
          if (!currentSession.value
              .isEditableByUser(userId!, accessibleContents!))
            const SizedBox.shrink()
          else
            IconButton(
              onPressed: () async {
                final result = await Navigator.of(context).pushNamed(
                  HomeRouter.editSessionPage,
                  arguments: {'session': currentSession.value},
                );
                if (result is Session) {
                  currentSession.value = result;
                  onSessionUpdated(result);
                }
              },
              icon: const Icon(Icons.settings),
            ),
        ],
        bottom: PreferredSize(
          preferredSize: Size.fromHeight(24),
          child: Padding(
            padding: HomePage.bodyPadding,
            child: TabBar(
              controller: tabController,
              labelColor: ColorManager.main,
              unselectedLabelColor: context.isDarkMode
                  ? ColorManager.darkSecondaryText
                  : ColorManager.secondaryText,
              dividerColor: ColorManager.main,
              tabs: [
                Tab(
                  height: 32,
                  text: context.l10n.session_details_page__tab_list,
                  iconMargin: EdgeInsets.zero,
                ),
                Tab(
                  height: 32,
                  text: context.l10n.session_details_page__tab_graph,
                  iconMargin: EdgeInsets.zero,
                ),
              ],
            ),
          ),
        ),
      ),
      body: SafeArea(
        child: Padding(
          padding: HomePage.bodyPadding.copyWith(top: 8),
          child: Stack(
            children: [
              TabBarView(
                controller: tabController,
                children: [
                  if (resourcePagingData.items.isEmpty)
                    EmptyView(
                      message: context.l10n.session_details_page__no_data,
                    )
                  else
                    RefreshIndicator(
                      onRefresh: () async {
                        ref
                            .read(resourceDataListControllerProvider(
                              teamId: teamId,
                              sessionId: currentSession.value.id!,
                            ).notifier)
                            .forceRefresh();

                        ref.invalidate(teamListControllerProvider);

                        await ref.read(resourceDataListControllerProvider(
                          teamId: teamId,
                          sessionId: currentSession.value.id!,
                        ).future);
                      },
                      child: SizedBox(
                        height: context.screenHeight,
                        child: SingleChildScrollView(
                          physics: const AlwaysScrollableScrollPhysics(),
                          child: Column(
                            children: [
                              ...resourcePagingData.items.mapIndexed(
                                (index, resource) => Container(
                                  margin: const EdgeInsetsDirectional.only(
                                    bottom: 8,
                                  ),
                                  child: ResourceCard(
                                    teamId: teamId,
                                    session: currentSession.value,
                                    resource: resource,
                                    isLastItem: index ==
                                            resourcePagingData.items.length -
                                                1 &&
                                        index != 0,
                                  ),
                                ),
                              ),
                              if (resourcePagingData.hasMore)
                                EndItemView(
                                  visibilityKey: Key(
                                    'EndItem_${resourcePagingData.items.length}',
                                  ),
                                  onScrollEnd: () {
                                    ref
                                        .read(
                                            resourceDataListControllerProvider(
                                          teamId: teamId,
                                          sessionId: currentSession.value.id!,
                                        ).notifier)
                                        .loadNext();
                                  },
                                )
                            ],
                          ),
                        ),
                      ),
                    ),
                  SessionScatterChart(
                    teamId: teamId,
                    sessionId: currentSession.value.id!,
                  ),
                ],
              ),
              Align(
                alignment: Alignment.bottomCenter,
                child: Padding(
                  padding: context.isPortrait
                      ? const EdgeInsets.only(right: 66, bottom: 10)
                      : const EdgeInsets.only(right: 66, bottom: 32),
                  child: const UsageLimitAlertSnackBar(),
                ),
              ),
            ],
          ),
        ),
      ),
      floatingActionButton: ListenableBuilder(
        listenable: tabController,
        builder: (context, child) {
          if (tabController.index == 0) {
            return isRecordingAvailable == true
                ? FloatingActionButton(
                    backgroundColor: Theme.of(context)
                        .floatingActionButtonTheme
                        .backgroundColor,
                    onPressed: () {
                      Navigator.of(context, rootNavigator: true).pushNamed(
                        AppRouter.recordingPage,
                        arguments: {
                          'sessionId': currentSession.value.id!,
                          'sessionCreatedAt':
                              currentSession.value.createdAt ?? DateTime.now(),
                          'teamId': teamId,
                        },
                      );
                    },
                    child: const Icon(Icons.videocam_outlined),
                  )
                : isRecordingAvailable == false
                    ? FloatingActionButton(
                        backgroundColor: ColorManager.secondaryText,
                        onPressed: () {
                          if (canSubscribe) {
                            final teams = teamList.valueOrNull;
                            if (teams == null || teams.hasLeft) return;
                            final team = teams.right
                                .firstWhereOrNull((t) => t.id == teamId);
                            goToSubscription.call(team);
                          }
                        },
                        child: Icon(
                          Icons.workspace_premium,
                          color: Colors.yellow[700],
                        ),
                      )
                    : FloatingActionButton(
                        backgroundColor: ColorManager.secondaryText,
                        onPressed: null,
                        child: const Icon(Icons.videocam_outlined),
                      );
          }
          return const SizedBox.shrink();
        },
      ),
    );
  }
}

