## 【推奨改善案】

### 統合的な修正版：
```dart
useEffect(() {
  bool isMounted = true;

  () async {
    try {
      final isSupported = await ref.read(cameraProvider.notifier).isDeviceSupported();

      // ログ出力
      debugPrint('Device support check result: $isSupported');

      if (!isSupported && isMounted && context.mounted) {
        _showUnsupportedDeviceDialog(context);
      }
    } catch (e, stackTrace) {
      debugPrint('Device support check failed: $e');
      debugPrint('Stack trace: $stackTrace');
      // 必要に応じてクラッシュレポート送信
    }
  }();

  return () => isMounted = false;
}, []);

@visibleForTesting
void _showUnsupportedDeviceDialog(BuildContext context) {
  // 重複チェック
  if (ModalRoute.of(context)?.isCurrent != true) return;

  showDialog<void>(
    context: context,
    barrierDismissible: false,
    builder: (context) => const UnsupportedDeviceDialog(),
  );
}
```

