```dart
useEffect(() {
  bool isMounted = true;

  () async {
    try {
      final isSupported = await ref.read(cameraProvider.notifier).isDeviceSupported();

      if (!isSupported && isMounted && context.mounted) {
        _showUnsupportedDeviceDialog(context);
      }
    } catch (e) {
      debugPrint('Device support check failed: $e');
    }
  }();

  return () => isMounted = false; // cleanup 関数の追加
}, []);
```

